 1	import type { FC } from 'react';
 2	
 3	import SectionHeading from '@components/headers/SectionHeading';
 4	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 5	import { isEmpty } from '@utils/helpers';
 6	import { useForkliftTranslation } from '@utils/i18n';
 7	
 8	import type { InventorySectionProps } from './utils/types';
 9	import { getInventorySectionByType } from './utils/utils';
10	
11	const InventorySection: FC<InventorySectionProps> = ({ data }) => {
12	  const { t } = useForkliftTranslation();
13	
14	  const { inventory, provider } = data;
15	
16	  if (isEmpty(provider) || isEmpty(inventory)) {
17	    return <span className="text-muted">{t('No inventory data available.')}</span>;
18	  }
19	
20	  const InventorySectionByType = getInventorySectionByType(provider?.spec?.type);
21	
22	  if (!InventorySectionByType) return null;
23	
24	  return (
25	    <PageSection variant={PageSectionVariants.light} className="forklift-page-section--details">
26	      <SectionHeading text={t('Provider inventory')} />
27	      <InventorySectionByType data={data} />
28	    </PageSection>
29	  );
30	};
31	
32	export default InventorySection;

